ps.pstext:
if !IsFeatureImplemented(FEAT_SME) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Rn);
let m : integer = UInt(Rm);
let g : integer = UInt('0'::Pg);
let s : integer = UInt('011'::Rs);
let t : integer = UInt(ZAt);
let offset : integer = UInt(off3);
let esize : integer{} = 16;
let vertical : boolean = V == '1';

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let dim : integer = VL DIV esize;
var base : bits(64);
var addr : bits(64);
let mask : bits(PL) = P{}(g);
var moffs : bits(64) = X{}(m);
let index : bits(32) = X{}(s);
let slice : integer = (UInt(index) + offset) MOD dim;
var result : bits(VL);
let mbytes : integer{} = esize DIV 8;
let contiguous : boolean = TRUE;
let nontemporal : boolean = FALSE;
let tagchecked : boolean = TRUE;
let accdesc : AccessDescriptor = CreateAccDescSME(MemOp_LOAD, nontemporal, contiguous,
                                                     tagchecked);

if n == 31 then
    if (AnyActiveElement{PL}(mask, esize) ||
          ConstrainUnpredictableBool(Unpredictable_CHECKSPNONEACTIVE)) then
        CheckSPAlignment();
    end;
    base = SP{64}();
else
    base = X{64}(n);
end;

for e = 0 to dim - 1 do
    addr = AddressAdd(base, UInt(moffs) * mbytes, accdesc);
    if ActivePredicateElement{PL}(mask, e, esize) then
        result[e*:esize] = Mem{esize}(addr, accdesc);
    else
        result[e*:esize] = Zeros{esize};
    end;
    moffs = moffs + 1;
end;

ZAslice{VL}(t, esize, vertical, slice) = result;
